import Foundation

func makeRequest(url: URL, isSecure: Bool, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) {
    var request = URLRequest(url: url)

    if isSecure {
        request.timeoutInterval = 10.0
        let configuration = URLSessionConfiguration.default
        configuration.httpAdditionalHeaders = ["User-Agent": "MyApp/1.0"]
        let session = URLSession(configuration: configuration, delegate: nil, delegateQueue: OperationQueue())
        let task = session.dataTask(with: request) { data, response, error in
            completionHandler(data, response, error)
        }
        task.resume()
    } else {
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            completionHandler(data, response, error)
        }
        task.resume()
    }
}

